css:
.heading {
    font-size: 2rem;
    color: rgb(68, 68, 68);
    padding-left: 1rem;
    margin-bottom: 1rem;
    border-left: .4rem solid var(--green);
}

.header-3 {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: #fff;
  box-shadow: 0 .5rem 1rem rgba(0,0,0,.1);
  position: sticky;   /* 👈 change this */
  top: 0;             /* stick to top */
  z-index: 10000;
  padding: 10px;
}

.header-3 .icons a{
  color:#666;
  font-size: 1.5rem;
  margin-left: 2rem;
}

.header-3 a:hover{
  color:var(--green);
}
.navbar {
    font-size: 22px;
}
.header-3 .navbar a{
  color:#666;
  margin-right: 2rem;
}
.header-3.active{
  position: fixed;
  top:0; left: 0; right: 0;
}


#menu-bar{
  font-size: 3rem;
  color:#666;
  border:.1rem solid #666;
  border-radius: .5rem;
  padding:.5rem 1.5rem;
  cursor: pointer;
  display: none;
}


@media (max-width:991px){

  .header-3{
    padding:0.5rem;
  }

  section{
    padding:1.5rem;
  }
  
  .home{
      padding:1rem ;
  }

}

@media (max-width:768px){

  #menu-bar{
    display: initial;
  }

  .header-3 .navbar{
    position: absolute;
    top:100%; left: 0; right: 0;
    background:#eee;
    padding:1rem 2rem;
    border-top: .1rem solid rgba(0,0,0,.3);
    clip-path: polygon(0 0, 100% 0, 100% 0, 0 0);
    display: flex;
    flex-direction: column;   /* ✅ stack children vertically */
  }

  .header-3 .navbar.active{
    clip-path: polygon(0 0, 100% 0, 100% 100%, 0% 100%);
  }

  .header-3 .navbar a,
  .header-3 .navbar .dropdown {
    display: block;            /* ✅ make all links & dropdown full width */
    margin:0.5rem 0;
    border-radius: .5rem;
    background:#fff;
    text-align: center;
    width: 100%;
  }

  /* Optional: make the dropdown menu full width on mobile */
  .header-3 .navbar .dropdown-menu {
    position: static;
    float: none;
    width: 100%;
    margin: 0;
    border: none;
    box-shadow: none;
  }
}


.home{
  padding-top: 0;
}

.home .home-slider{
  box-shadow: 0 .5rem 1rem rgba(0,0,0,.1);
  border:.1rem solid rgba(0,0,0,.3);
  border-top: 0;
}

.home .home-slider .box{
  background-size: cover !important;
  background-position: center !important;
  min-height: 30rem;
  position: relative;
}

.home .home-slider .box .content{
  position: absolute;
  top:50%; left: 65%;
  transform: translateY(-50%);
  max-width: 50rem;
}

.home .home-slider .box .content span{
  font-size: 30px;
  color:#ffffff;
  font-weight: bolder;
  text-shadow: 2px 2px black;
}
.content .btn{
  font-size: 20px;
  margin-top: 21px;

}

section{
  padding:1.5rem 9%;
}

a {
  text-decoration: none !important;
  color: inherit; /* Keeps text color unchanged */
}
.banner-container{
  display: flex;
  gap:1.5rem;
  flex-wrap: nowwrap;  /* ✅ allow wrapping */
}

.banner-container .banner{
  flex:1 1 40rem;
  height:25rem;
  border:.1rem solid rgba(0,0,0,.3);
  box-shadow: 0 .5rem 1rem rgba(0,0,0,.1);
  overflow: hidden;
  position: relative;
}

.banner-container .banner .content{
  position: absolute;
  top:50%; left: 4%;
  transform: translateY(-50%);
}

.banner-container .banner img{
  height: 100%;
  width:100%;
  object-fit: cover;
}

.banner-container .banner .content span{
  color:#666;
  font-size:21px;
}

.banner-container .banner .content h3{
  color:#333;
  font-size:30px;
}

.banner-container .banner:hover img{
  transform: scale(1.2);
}

.product .box-container{
  display: flex;
  flex-wrap: wrap;
  gap:2rem;
}

.product .box-container .box{
  flex:1 1 24rem;
  max-width: 35rem;
  border-radius: 2rem;
  border:.1rem solid rgba(0,0,0,.3);
  box-shadow: 0 .5rem 1rem rgba(0,0,0,.1);
  text-align: center;
  position: relative;
  overflow: hidden;
  min-height: 350px;
  justify-content: space-between;
}

.product .box-container .box img{
  /*height: 30rem;*/
  height: 250px;
  width:100%;
  border-bottom:.1rem solid rgba(0,0,0,.3);
  object-fit: contain;
}


.product .box-container .box .quantity {
  padding-top: 10px;
}
.product .box-container .box .quantity span{
  font-size: 20px;
}
.product .box-container .box .icons{
  position: absolute;
  top:1rem; right:-8rem;
  display: flex;
  flex-flow: column;
  background:#fff;
  border-radius: 5rem;
  padding:.5rem;
  box-shadow: 0 .5rem 1rem rgba(0,0,0,.1);
}

.product .box-container .box:hover .icons{
  right:1rem;
}

.product .box-container .box .icons a{
  height: 4rem;
  width:4rem;
  /*line-height: 4rem;*/
  color:#333;
  border-radius: 5rem;
  margin:.1rem;
}

.product .box-container .box .icons a:hover{
  color:#fff;
  background:var(--green);
}

.product .box-container .box h3{
  color:#333;
}

.product .box-container .box .quantity input{
  text-align: center;
  background:rgba(0,0,0,.1);
}

.product .box-container .box .price{
  font-weight: bolder;
  color:var(--green);
  font-size: 20px;
    padding-top: 12px;
}
.product .rating i {
    color: #f1c40f;
    margin: 2px;
}
.product .box-container .box .price span{
  text-decoration: line-through;
  color:#999;
}
.product .box-container .box .btn{
    display: block;
    margin: 1rem;
}

.contact .row {
  display: flex;
  flex-wrap: wrap;
  gap: 2rem;
  border: .1rem solid rgba(0,0,0,.3);
  padding: 1rem;
  border-radius: 1rem;
  background: #fff;
}

.contact .row .map {
  flex: 1 1 34rem;
}

.contact .row .map iframe {
  width: 100%;
  height: 100%;
  min-height: 400px;
  border-radius: 1rem;
  border: 0;
}

.contact .row form {
  flex: 1 1 34rem;
  padding: 1rem;
  background: #f9f9f9;
  border-radius: 1rem;
  box-shadow: 0 .5rem 1rem rgba(0,0,0,.1);
}

.contact .row form .inputBox {
  position: relative;
  margin-bottom: 2rem;
}

.contact .row form .inputBox input,
.contact .row form .inputBox textarea {
  width: 100%;
  border: none;
  border-bottom: .1rem solid rgba(0,0,0,.3);
  padding: 1rem 0;
  font-size: 1.6rem;
  background: transparent;
  outline: none;
  color: #333;
}

.contact .row form .inputBox textarea {
  resize: none;
  height: 12rem;
}

.contact .row form .inputBox label {
  position: absolute;
  top: 1.2rem; 
  left: 0;
  font-size: 1.6rem;
  color: #666;
  transition: 0.3s;
}

.contact .row form .inputBox input:focus ~ label,
.contact .row form .inputBox textarea:focus ~ label,
.contact .row form .inputBox input:valid ~ label,
.contact .row form .inputBox textarea:valid ~ label {
  top: -0.8rem;
  font-size: 1.3rem;
  color: var(--green);
}

