/*  display: inline-block;*/
/*  background: var(--green);*/
/*  color: #fff;*/
/*  padding: 1rem 2rem;*/
/*  border-radius: .5rem;*/
/*  font-size: 1.6rem;*/
/*  cursor: pointer;*/
/*  border: none;*/
/*}*/

.contact .row form .btn:hover {
  background: #333;
}


/* Footer section */
.footer {
    background: #2c3e50;   /* Dark background */
    color: #fff;
    padding: 50px 20px;
    font-family: 'Poppins', sans-serif;
}

.footer .box-container {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 30px;
    max-width: 1200px;
    margin: auto;
}

.footer .box h3 {
    font-size: 20px;
    color: #f1c40f;
    margin-bottom: 15px;
    position: relative;
}

.footer .box h3::after {
    content: '';
    display: block;
    width: 40px;
    height: 3px;
    background: #f1c40f;
    margin-top: 5px;
    border-radius: 3px;
}

.footer .box p {
    font-size: 14px;
    line-height: 1.6;
    color: #ccc;
}

.footer .box a {
    display: block;
    font-size: 14px;
    color: #ccc;
    margin: 8px 0;
    transition: 0.3s;
    text-decoration: none;
}

.footer .box a:hover {
    color: #f1c40f;
    padding-left: 5px;
}

/* Scroll top button */
.scroll-top {
    position: fixed;
    bottom: 20px;
    right: 20px;
    background: #f1c40f;
    color: #2c3e50;
    font-size: 20px;
    padding: 10px 15px;
    border-radius: 50%;
    text-decoration: none;
    box-shadow: 0 4px 6px rgba(0,0,0,0.3);
    transition: 0.3s ease;
    display: none; /* Initially hidden */
}

.scroll-top:hover {
    background: #fff;
    color: #f1c40f;
}

/* Show scroll button when scrolled */
body.scrolled .scroll-top {
    display: inline-block;
}

/* Responsive */
@media (max-width: 768px) {
    .footer {
        text-align: center;
    }
    .footer .box h3::after {
        margin: 5px auto 0;
    }
}

